import{bQ as a,aL as i,u as t,G as e}from"./chunks/framework.D06dwy5q.js";const c=JSON.parse('{"title":"16｜预处理管线：调用前整理上下文","description":"","frontmatter":{},"headers":[],"relativePath":"19.AIOps/03.循环与控制设计/16-预处理管线-调用前整理上下文.md","filePath":"19.AIOps/03.循环与控制设计/16-预处理管线-调用前整理上下文.md","lastUpdated":null}'),n={name:"19.AIOps/03.循环与控制设计/16-预处理管线-调用前整理上下文.md"};function p(l,s,h,k,r,o){return i(),t("div",null,[...s[0]||(s[0]=[e(`<h1 id="_16-预处理管线-调用前整理上下文" tabindex="-1">16｜预处理管线：调用前整理上下文 <a class="header-anchor" href="#_16-预处理管线-调用前整理上下文" aria-label="Permalink to &quot;16｜预处理管线：调用前整理上下文&quot;">​</a></h1><p>上一篇讲完继续工作，循环与控制设计的核心都到位了。但有两个执行细节要补，本篇讲第一个：每轮调 API 前，消息要先经过预处理。</p><p>第 10 篇讲过压缩策略——上下文太长时怎么办。本篇是另一个角度：不是&quot;太长才压缩&quot;，而是&quot;每轮调用前都过一遍管线，从轻到重处理，够用就停&quot;。它和压缩策略用的是同一套手段，但定位不同：压缩是被动应对超长，预处理是主动的调用前流程。</p><h2 id="为什么每轮都要预处理" tabindex="-1">为什么每轮都要预处理 <a class="header-anchor" href="#为什么每轮都要预处理" aria-label="Permalink to &quot;为什么每轮都要预处理&quot;">​</a></h2><p>循环每轮调 API 前，消息列表可能积累了各种问题：上一轮工具返回的大段日志还没折叠、早期对话已经过时但还留着、格式噪声没清理。如果不管直接发，token 浪费、模型注意力分散、甚至触发上下文超长。</p><p>预处理管线在调用前把这些处理掉。不是等到超长才动手，是每轮调用前过一遍，把上下文维持在健康状态。</p><h2 id="从轻到重的管线" tabindex="-1">从轻到重的管线 <a class="header-anchor" href="#从轻到重的管线" aria-label="Permalink to &quot;从轻到重的管线&quot;">​</a></h2><p>和第 10 篇的压缩策略同源，从轻到重三层：</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">def</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> preprocess</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(messages, budget, client):</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # 第一层：轻量整理（零成本）</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    messages </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> light_cleanup(messages)</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> token_count(messages) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> budget </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0.9</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">        return</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> messages</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # 第二层：上下文折叠（低成本）</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    messages </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> fold_messages(messages, budget)</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> token_count(messages) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> budget </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0.9</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">        return</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> messages</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # 第三层：AutoCompact（高成本，调模型）</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    messages </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> auto_compact(messages, client, budget)</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    return</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> messages</span></span></code></pre></div><p>第一层轻量整理：去掉空消息、重复内容、过期时间戳标记。不改变实质信息，成本接近零。</p><p>第二层上下文折叠：把详细内容折叠成摘要，保留关键字段。工具返回的 500 行日志折叠成一行摘要，早期几轮对话折叠成&quot;已确认事实&quot;。靠规则或模板，不调模型。</p><p>第三层 AutoCompact：前两层不够时调模型做摘要。成本最高，放最后。</p><h2 id="够用就停" tabindex="-1">够用就停 <a class="header-anchor" href="#够用就停" aria-label="Permalink to &quot;够用就停&quot;">​</a></h2><p>这是预处理管线最关键的设计：够用就停，不每次走完三层。</p><p>固定流程——每次都先整理、再折叠、再摘要——违背管线核心设计。生产环境里多数请求只需要轻量整理，少数需要走到折叠，只有少数长会话才触发 AutoCompact。固定走完三层会让大部分请求多付不必要的成本。</p><p>每一层试完都检查够不够，够了就停。这个&quot;够用&quot;的判断是 <code>token_count(messages) &lt; budget * 0.9</code>——留 10% 余量，不卡着上限。</p><h2 id="管线顺序不能乱" tabindex="-1">管线顺序不能乱 <a class="header-anchor" href="#管线顺序不能乱" aria-label="Permalink to &quot;管线顺序不能乱&quot;">​</a></h2><p>三层顺序是按成本和破坏程度递增排的。轻量整理成本最低、破坏最小（不丢实质信息），先走。折叠成本中等、会丢细节，第二。AutoCompact 成本最高、会丢最多信息，最后。</p><p>如果反过来——先 AutoCompact，再折叠，再整理——会浪费高成本操作在不必要的地方。AutoCompact 一次调用模型的钱花了，结果轻量整理本来就能释放足够空间。顺序按成本递增，让贵的操作尽量不被触发。</p><h2 id="压缩必须保留用户消息" tabindex="-1">压缩必须保留用户消息 <a class="header-anchor" href="#压缩必须保留用户消息" aria-label="Permalink to &quot;压缩必须保留用户消息&quot;">​</a></h2><p>和第 10 篇一样，预处理压缩时必须保留用户消息和用户约束。</p><p>&quot;不要用某技术栈&quot;&quot;只看最近一小时&quot;这类约束最容易在摘要中丢失。一旦丢失，后续轮次就会破坏这些约束。预处理 prompt 要明确要求保留用户约束、已确认事实、待确认项，可以丢弃工具调用的中间过程和重复确认消息。</p><h2 id="预处理不是每次请求都全走" tabindex="-1">预处理不是每次请求都全走 <a class="header-anchor" href="#预处理不是每次请求都全走" aria-label="Permalink to &quot;预处理不是每次请求都全走&quot;">​</a></h2><p>这里要纠正一个常见做法：把预处理写成固定的三步流程，每次请求都走完。</p><p>预处理管线的核心是&quot;按需触发&quot;。轻量整理可以每轮都做（成本接近零），但折叠和 AutoCompact 应该只在轻量整理不够时才触发。判断条件是 token 是否接近预算——离预算远就只做轻量整理，接近了才往下走。</p><p>具体各层占比以本项目 eval 为准，不套用别人的统计数字。不同任务、不同对话长度，各层触发比例不同。</p><h2 id="预处理之后" tabindex="-1">预处理之后 <a class="header-anchor" href="#预处理之后" aria-label="Permalink to &quot;预处理之后&quot;">​</a></h2><p>预处理管线让每轮调 API 前的上下文都是健康的。调用前的部分讲完了，接下来是调用后：模型一次可能返回多个工具调用，这些工具调用怎么执行——串行还是并行，怎么决定。</p><p>下一篇讲流式与并发。这是循环与控制设计的最后一篇执行细节。</p>`,29)])])}const E=a(n,[["render",p]]);export{c as __pageData,E as default};
